import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CashFlowProjection {
  year: number;
  cashFlow: number;
}

interface PropertyData {
  property: {
    address: string;
    rentalYield: number;
    appreciationRate: number;
  };
  cashFlowProjection: CashFlowProjection[];
}

export default function Widget() {
  const propertyData = response.data as PropertyData;
  const { property, cashFlowProjection } = propertyData;
  const clipPathId = React.useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Property Address
            </Typography>
            <Typography variant="h6" fontWeight={700} sx={{ color: '#4CAF50' }}>
              {property.address}
            </Typography>
          </Box>

          <Stack direction="row" spacing={3}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Rental Yield
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {property.rentalYield}%
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Appreciation Rate
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {property.appreciationRate}%
              </Typography>
            </Box>
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: cashFlowProjection.map(c => c.cashFlow),
                  color: '#FFC107',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: cashFlowProjection.map(c => c.year.toString()),
                  id: 'years',
                },
              ]}
              yAxis={[{ id: 'cashFlow' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="years"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="cashFlow"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
